@Composable
fun ExplorerScreen(viewModel: ConduitViewModel) {
    val context = LocalContext.current
    val scope = rememberCoroutineScope()
    val focusManager = LocalFocusManager.current
    val listState = androidx.compose.foundation.lazy.rememberLazyListState()
    var isSearching by remember { mutableStateOf(false) }
    var searchQuery by remember { mutableStateOf("") }

    val currentCategory = viewModel.explorerCategory
    val isScanning = viewModel.isScanningExplorer

    LaunchedEffect(Unit) {
        viewModel.refreshDashboard(context)
    }

    LaunchedEffect(viewModel.explorerFiles) {
        if (viewModel.highlightedPath != null) {
            val index = viewModel.explorerFiles.indexOfFirst { it.path == viewModel.highlightedPath }
            if (index != -1) {
                listState.animateScrollToItem(index)
                kotlinx.coroutines.delay(3000)
                viewModel.highlightedPath = null
            }
        }
    }

    val showCreateDialog = viewModel.showExplorerCreateDialog
    var createType by remember { mutableStateOf("File") }
    var newItemName by remember { mutableStateOf("") }

    // Ops State
    val selectedFiles = viewModel.selectedFiles
    var showRenameDialog by remember { mutableStateOf(false) }
    var showPropertyDialog by remember { mutableStateOf(false) }
    var showMoreMenu by remember { mutableStateOf(false) }
    val loadFolder = { path: String -> viewModel.loadExplorerFolder(path) }
    val openCategory = { cat: String -> viewModel.openExplorerCategory(context, cat) }

    BackHandler(enabled = selectedFiles.isNotEmpty() || currentCategory != null) {

        if (selectedFiles.isNotEmpty()) {
            viewModel.clearSelection()
        } else if (viewModel.explorerReturnCategory != null) {
            viewModel.explorerCategory = viewModel.explorerReturnCategory
            viewModel.explorerReturnCategory = null
        } else if (currentCategory == "Internal Storage" && viewModel.explorerPath != "/storage/emulated/0") {
            val parent = java.io.File(viewModel.explorerPath).parent ?: "/storage/emulated/0"
            viewModel.loadExplorerFolder(parent)
        } else {
            viewModel.explorerCategory = null
        }
    }

    Box(modifier = Modifier
        .fillMaxSize()
        .pointerInput(Unit) {
            detectTapGestures(onTap = {
                isSearching = false
                focusManager.clearFocus()
            })
        }
    ) {
        Column(modifier = Modifier.fillMaxSize().padding(horizontal = 20.dp)) {
            // Header with Expanding Search
            Row(
                modifier = Modifier.fillMaxWidth().padding(top = 20.dp, bottom = 10.dp),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                if (!isSearching) {
                    Text("Nexus Explorer", style = MaterialTheme.typography.headlineSmall, fontWeight = FontWeight.Bold)
                }

                ExpandingSearch(
                    isExpanded = isSearching,
                    query = searchQuery,
                    onQueryChange = { searchQuery = it },
                    onToggle = { isSearching = !isSearching },
                    onSearch = {
                        viewModel.explorerCategory = "Search Results"
                        viewModel.isScanningExplorer = true
                        scope.launch(Dispatchers.IO) {
                            val results = FileScanner.searchFilesNative(context, searchQuery)
                            withContext(Dispatchers.Main) {
                                viewModel.explorerFiles = results
                                viewModel.isScanningExplorer = false
                            }
                        }
                    }
                )
            }

            LazyColumn(modifier = Modifier.fillMaxSize()) {
                item { Spacer(modifier = Modifier.height(15.dp)) }

                // Storage Card
                item {
                    StorageUsageCard(
                        label = viewModel.storageLabel, 
                        percent = viewModel.storagePercent,
                        onClick = { openCategory("Internal Storage") }
                    )
                }

                item { Spacer(modifier = Modifier.height(25.dp)) }

                // Category Grid
                item {
                    CategoryGrid(onCatClick = { openCategory(it) })
                }

                item { Spacer(modifier = Modifier.height(30.dp)) }

                // Recent Files Section
                item {
                    Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                        Text("Recent Files", style = MaterialTheme.typography.titleMedium, fontWeight = FontWeight.SemiBold)
                        Text(
                            text = "View All", 
                            color = Color(0xFF00E5FF), 
                            style = MaterialTheme.typography.labelLarge,
                            modifier = Modifier.clickable { openCategory("Recent Files") }
                        )
                    }
                    Spacer(modifier = Modifier.height(15.dp))
                }

                items(viewModel.dashboardRecentFiles) { file ->
                    FileRow(
                        file = file, 
                        isHighlighted = selectedFiles.contains(file),
                        onClick = {
                            if (selectedFiles.isNotEmpty()) {
                                viewModel.toggleSelection(file)
                            } else {
                            val f = java.io.File(file.path)
                                                if (f.isDirectory) {
                        viewModel.explorerCategory = "Internal Storage"
                        loadFolder(f.absolutePath)
                            } else {
                                val textExts = listOf("txt", "py", "js", "json", "kt", "java", "html", "css", "md", "yml", "yaml", "c", "cpp", "h")
                                if (textExts.contains(f.extension.lowercase())) {
                                    viewModel.openFileForEditing(f)
                                } else {
                                    try {
                                        val intent = android.content.Intent(android.content.Intent.ACTION_VIEW)
                                        intent.setDataAndType(androidx.core.content.FileProvider.getUriForFile(context, "${context.packageName}.provider", f), "*/*")
                                        intent.addFlags(android.content.Intent.FLAG_GRANT_READ_URI_PERMISSION)
                                        context.startActivity(android.content.Intent.createChooser(intent, "Open with"))
                                    } catch (e: Exception) { }
                                                                    }
                                }
                            },
                            onLongClick = { viewModel.toggleSelection(file) }
                        )
                    Spacer(modifier = Modifier.height(12.dp))
                }
            }
        }

        // Dynamic Category Overlay
        AnimatedVisibility(
            visible = currentCategory != null,
            enter = slideInHorizontally(initialOffsetX = { it }),
            exit = slideOutHorizontally(targetOffsetX = { it })
        ) {
            Surface(modifier = Modifier.fillMaxSize(), color = Color(0xFF0D1117)) {
                Column(modifier = Modifier.fillMaxSize()) {
                    Row(
                        modifier = Modifier.fillMaxWidth().background(Color(0xFF161B22)).padding(top = 12.dp, start = 8.dp, bottom = 8.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        IconButton(onClick = {
                            viewModel.clearSelection()
                            if (currentCategory == "Internal Storage" && viewModel.explorerPath != "/storage/emulated/0") {
                                val parent = java.io.File(viewModel.explorerPath).parent ?: "/storage/emulated/0"
                                loadFolder(parent)
                            } else {
                                viewModel.explorerCategory = null
                            }
                        }) {
                            Icon(Icons.Default.ArrowBack, null, tint = Color.White)
                        }
                        val isInternalRoot = currentCategory == "Internal Storage" && viewModel.explorerPath == "/storage/emulated/0"

                        IconButton(onClick = { viewModel.explorerCategory = null }) {
                            Icon(Icons.Default.Home, null, tint = Color.Gray, modifier = Modifier.size(20.dp))
                        }

                        val breadcrumbScrollState = rememberScrollState()
                        Row(
                            modifier = Modifier
                                .weight(1f)
                                .horizontalScroll(breadcrumbScrollState),
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            if (currentCategory == "Internal Storage") {
                                val rootPath = "/storage/emulated/0"
                                val currentPath = viewModel.explorerPath

                                // Root Link
                                Text(
                                    text = "Root",
                                    color = if (currentPath == rootPath) Color(0xFF00E5FF) else Color.Gray,
                                    fontWeight = FontWeight.Bold,
                                    fontSize = 14.sp,
                                    modifier = Modifier.clickable { viewModel.loadExplorerFolder(rootPath) }
                                )

                                if (currentPath != rootPath) {
                                    val subPath = currentPath.removePrefix(rootPath).removePrefix("/")
                                    val segments = subPath.split("/")
                                    var accumulatedPath = rootPath

                                    segments.forEach { segment ->
                                        if (segment.isNotEmpty()) {
                                            accumulatedPath += "/$segment"
                                            val targetPath = accumulatedPath // Capture for lambda

                                            Icon(Icons.Default.ChevronRight, null, modifier = Modifier.size(14.dp), tint = Color.Gray)
                                            Text(
                                                text = segment,
                                                color = if (currentPath == targetPath) Color(0xFF00E5FF) else Color.Gray,
                                                fontWeight = if (currentPath == targetPath) FontWeight.Bold else FontWeight.Normal,
                                                fontSize = 14.sp,
                                                modifier = Modifier.clickable { viewModel.loadExplorerFolder(targetPath) }
                                            )
                                        }
                                    }
                                }
                            } else {
                                // Fallback for other categories (Images, Search, etc.)
                                Text("Explorer", color = Color.Gray, fontSize = 14.sp)
                                Icon(Icons.Default.ChevronRight, null, modifier = Modifier.size(14.dp), tint = Color.Gray)
                                Text(
                                    text = currentCategory ?: "",
                                    color = Color(0xFF00E5FF),
                                    fontWeight = FontWeight.Bold,
                                    fontSize = 14.sp
                                )
                            }
                        }


                    }

                    if (isScanning) {
                        Box(modifier = Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
                            CircularProgressIndicator(color = Color(0xFF00E5FF))
                        }
                    } else if (viewModel.explorerFiles.isEmpty()) {
                        Box(modifier = Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {
                            Column(horizontalAlignment = Alignment.CenterHorizontally) {
                                Icon(
                                    Icons.Default.FolderOpen, 
                                    null, 
                                    modifier = Modifier.size(64.dp), 
                                    tint = Color.Gray.copy(alpha = 0.5f)
                                )
                                Spacer(modifier = Modifier.height(16.dp))
                                Text(
                                    "No one is home.", 
                                    style = MaterialTheme.typography.titleMedium, 
                                    color = Color.Gray
                                )
                                Text(
                                    "This folder is empty or no files match.", 
                                    style = MaterialTheme.typography.bodySmall, 
                                    color = Color.Gray.copy(alpha = 0.7f)
                                )
                            }
                        }
                    } else {
                                        LazyColumn(
                        modifier = Modifier.fillMaxSize().padding(16.dp), 
                        state = listState
                    ) {
                            items(viewModel.explorerFiles) {
                                    file ->
                                FileRow(
                                        file = file, 
