async function sendData() {
    const input = document.getElementById('input-text');
    const text = input.value.trim();
    if (!text) return;

    const btn = document.getElementById('send-btn');
    const originalText = btn.innerHTML;
    btn.innerHTML = '<span class="animate-pulse">Syncing...</span>';
    btn.disabled = true;

    // Add new item to top
    const newItem = {
        id: Date.now(),
        text: text,
        date: new Date().toISOString()
    };

    // Update local first for speed
    localClips.unshift(newItem);

    // Limit to last 50 items to save space
    if (localClips.length > 50) localClips = localClips.slice(0, 50);

    // Push to DB
    const { error } = await db
        .from('clips')
        .update({ content: JSON.stringify(localClips) })
        .eq('slug', ROOM_SLUG);

    if (!error) {
        input.value = '';
        showToast('Sent to Vault');
        switchTab('read');
    } else {
        showToast('Error syncing');
    }

    btn.innerHTML = originalText;
    btn.disabled = false;
}

